  1→/**
  2→ * Property-based tests using fast-check for protocol types and SymExpr.
  3→ *
  4→ * Validates serialization round-trips and structural invariants that
  5→ * hand-written fixtures might miss.
  6→ */
  7→import fc from "fast-check";
  8→import ts from "typescript";
  9→import type {
 10→  BinOpKind,
 11→  UnOpKind,
 12→  SymExpr,
 13→  SymExprConst,
 14→  TypeInfo,
 15→  ComplexKind,
 16→  BranchType,
 17→  BranchDecision,
 18→  SymConstraint,
 19→  ErrorCode,
 20→  SideEffect,
 21→  PerformanceMetrics,
 22→  TraceEvent,
 23→  ScopeEvent,
 24→  HandshakeRequest,
 25→  AnalyzeRequest,
 26→  ExecuteRequest,
 27→  ShutdownRequest,
 28→  Request,
 29→  HandshakeResponse,
 30→  AnalyzeResponse,
 31→  ErrorResponse,
 32→  Response,
 33→  FunctionAnalysis,
 34→  ParamInfo,
 35→  BranchInfo,
 36→  ErrorInfo,
 37→} from "./protocol.js";
 38→import { PROTOCOL_VERSION } from "./protocol.js";
 39→import { buildSymExpr, buildSymExprWithFlow } from "./instrumentor.js";
 40→
 41→// ---------------------------------------------------------------------------
 42→// Arbitraries — leaf types
 43→// ---------------------------------------------------------------------------
 44→
 45→const arbIdent = fc.stringMatching(/^[a-zA-Z_][a-zA-Z0-9_]{0,12}$/);
 46→const arbShortString = fc.string({ maxLength: 30 });
 47→
 48→const arbBinOpKind: fc.Arbitrary<BinOpKind> = fc.constantFrom(
 49→  "eq", "ne", "lt", "le", "gt", "ge",
 50→  "add", "sub", "mul", "div", "mod",
 51→  "and", "or",
 52→  "bitwise_and", "bitwise_or", "bitwise_xor",
 53→  "in", "instance_of",
 54→);
 55→
 56→const arbUnOpKind: fc.Arbitrary<UnOpKind> = fc.constantFrom(
 57→  "not", "neg", "bitwise_not", "typeof",
 58→);
 59→
 60→const arbComplexKind: fc.Arbitrary<ComplexKind> = fc.constantFrom(
 61→  "date", "date_time", "time", "duration",
 62→  "reg_exp", "char", "symbol",
 63→  "big_int", "big_decimal", "complex", "rational", "range",
 64→  "buffer", "bit_set",
 65→  "error", "option", "result",
 66→  "closure", "iterator",
 67→  "url", "ip_address",
 68→  "uuid", "path",
 69→  "money", "sem_ver", "email", "mime_type", "color", "geo_point", "locale",
 70→  "rune", "go_byte",
 71→);
 72→
 73→const arbBranchType: fc.Arbitrary<BranchType> = fc.constantFrom(
 74→  "if", "else_if", "switch", "ternary",
 75→  "logical_and", "logical_or", "while", "for",
 76→);
 77→
 78→const arbErrorCode: fc.Arbitrary<ErrorCode> = fc.constantFrom(
 79→  "file_not_found", "function_not_found", "parse_error",
 80→  "instrumentation_failed", "execution_timeout", "execution_crash",
 81→  "version_mismatch", "invalid_request", "internal_error",
 82→);
 83→
 84→// ---------------------------------------------------------------------------
 85→// Arbitraries — recursive types
 86→// ---------------------------------------------------------------------------
 87→
 88→const arbSymExprConst: fc.Arbitrary<SymExprConst> = fc.oneof(
 89→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("int" as const), value: fc.integer({ min: -10000, max: 10000 }) }),
 90→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("float" as const), value: fc.integer({ min: -1000, max: 1000 }) }),
 91→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("str" as const), value: arbShortString }),
 92→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("bool" as const), value: fc.boolean() }),
 93→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("null" as const) }),
 94→  fc.record({ kind: fc.constant("const" as const), type: fc.constant("undefined" as const) }),
 95→);
 96→
 97→const arbSymExpr: fc.Arbitrary<SymExpr> = fc.letrec<{ expr: SymExpr }>(tie => ({
 98→  expr: fc.oneof(
 99→    { depthIdentifier: "symexpr", maxDepth: 3 },
100→    fc.record({
101→      kind: fc.constant("param" as const),
102→      name: arbIdent,
103→      path: fc.array(arbIdent, { maxLength: 3 }),
104→    }),
105→    arbSymExprConst,
106→    fc.record({ kind: fc.constant("unknown" as const) }),
107→    fc.record({
108→      kind: fc.constant("bin_op" as const),
109→      op: arbBinOpKind,
110→      left: tie("expr"),
111→      right: tie("expr"),
112→    }),
113→    fc.record({
114→      kind: fc.constant("un_op" as const),
115→      op: arbUnOpKind,
116→      operand: tie("expr"),
117→    }),
118→  ),
119→})).expr;
120→
121→const arbTypeInfoLeaf: fc.Arbitrary<TypeInfo> = fc.oneof(
122→  fc.record({ kind: fc.constant("int" as const) }),
123→  fc.record({ kind: fc.constant("float" as const) }),
124→  fc.record({ kind: fc.constant("str" as const) }),
125→  fc.record({ kind: fc.constant("bool" as const) }),
126→  fc.record({ kind: fc.constant("unknown" as const) }),
127→  fc.record({ kind: fc.constant("opaque" as const), label: arbIdent }),
128→);
129→
130→const arbTypeInfo: fc.Arbitrary<TypeInfo> = fc.letrec<{ ti: TypeInfo }>(tie => ({
131→  ti: fc.oneof(
132→    { depthIdentifier: "typeinfo", maxDepth: 2 },
133→    arbTypeInfoLeaf,
134→    fc.record({ kind: fc.constant("array" as const), element: tie("ti") }),
135→    fc.record({
136→      kind: fc.constant("nullable" as const),
137→      inner: tie("ti"),
138→    }),
139→    fc.record({
140→      kind: fc.constant("union" as const),
141→      variants: fc.array(tie("ti"), { minLength: 2, maxLength: 4 }),
142→    }),
143→  ),
144→})).ti;
145→
146→// ---------------------------------------------------------------------------
147→// Arbitraries — protocol records
148→// ---------------------------------------------------------------------------
149→
150→const arbSymConstraint: fc.Arbitrary<SymConstraint> = fc.oneof(
151→  fc.record({ kind: fc.constant("expr" as const), expr: arbSymExpr }),
152→  fc.record({ kind: fc.constant("unknown" as const), hint: arbShortString }),
153→);
154→
155→const arbBranchDecision: fc.Arbitrary<BranchDecision> = fc.record({
156→  branch_id: fc.nat(100),
157→  line: fc.integer({ min: 1, max: 500 }),
158→  taken: fc.boolean(),
159→  constraint: arbSymConstraint,
160→});
161→
162→const arbScopeEvent: fc.Arbitrary<ScopeEvent> = fc.oneof(
163→  fc.record({ kind: fc.constant("loop_enter" as const), loop_id: fc.nat(20) }),
164→  fc.record({ kind: fc.constant("loop_exit" as const), loop_id: fc.nat(20) }),
165→  fc.record({ kind: fc.constant("call_enter" as const), call_site_id: fc.nat(20) }),
166→  fc.record({ kind: fc.constant("call_exit" as const), call_site_id: fc.nat(20) }),
167→);
168→
169→const arbTraceEvent: fc.Arbitrary<TraceEvent> = fc.oneof(
170→  fc.record({ type: fc.constant("branch" as const), decision: arbBranchDecision }),
171→  fc.record({ type: fc.constant("scope" as const), event: arbScopeEvent }),
172→);
173→
174→const arbPerformanceMetrics: fc.Arbitrary<PerformanceMetrics> = fc.record({
175→  wall_time_ms: fc.nat(10000),
176→  cpu_time_us: fc.nat(10000000),
177→  heap_used_bytes: fc.nat(100000000),
178→  heap_allocated_bytes: fc.nat(100000000),
179→});
180→
181→const arbErrorInfo: fc.Arbitrary<ErrorInfo> = fc.record({
182→  error_type: arbIdent,
183→  message: arbShortString,
184→  stack: fc.option(arbShortString, { nil: null }),
185→});
186→
187→const arbSideEffect: fc.Arbitrary<SideEffect> = fc.oneof(
188→  fc.record({ kind: fc.constant("console_output" as const), level: arbIdent, message: arbShortString }),
189→  fc.record({ kind: fc.constant("global_mutation" as const), name: arbIdent }),
190→  fc.record({
191→    kind: fc.constant("thrown_error" as const),
192→    error_type: arbIdent,
193→    message: arbShortString,
194→    stack: fc.option(arbShortString, { nil: null }),
195→  }),
196→);
197→
198→const arbParamInfo: fc.Arbitrary<ParamInfo> = fc.record({
199→  name: arbIdent,
200→  type: arbTypeInfo,
201→});
202→
203→const arbBranchInfo: fc.Arbitrary<BranchInfo> = fc.record({
204→  id: fc.nat(100),
205→  line: fc.integer({ min: 1, max: 500 }),
206→  condition_text: arbShortString,
207→  condition: fc.option(arbSymExpr, { nil: null }),
208→  branch_type: arbBranchType,
209→});
210→
211→const arbFunctionAnalysis: fc.Arbitrary<FunctionAnalysis> = fc.record({
212→  name: arbIdent,
213→  exported: fc.boolean(),
214→  params: fc.array(arbParamInfo, { maxLength: 4 }),
215→  branches: fc.array(arbBranchInfo, { maxLength: 4 }),
216→  dependencies: fc.constant([]),
217→  return_type: arbTypeInfo,
218→  start_line: fc.integer({ min: 1, max: 500 }),
219→  end_line: fc.integer({ min: 1, max: 500 }),
220→});
221→
222→// ---------------------------------------------------------------------------
223→// Arbitraries — full protocol messages
224→// ---------------------------------------------------------------------------
225→
226→const arbRequest: fc.Arbitrary<Request> = fc.oneof(
227→  fc.record({
228→    protocol_version: fc.constant(PROTOCOL_VERSION),
229→    id: fc.nat(1000),
230→    command: fc.constant("handshake" as const),
231→    capabilities: fc.array(arbIdent, { maxLength: 3 }),
232→  }) as fc.Arbitrary<HandshakeRequest>,
233→  fc.record({
234→    protocol_version: fc.constant(PROTOCOL_VERSION),
235→    id: fc.nat(1000),
236→    command: fc.constant("analyze" as const),
237→    file: arbIdent,
238→  }) as fc.Arbitrary<AnalyzeRequest>,
239→  fc.record({
240→    protocol_version: fc.constant(PROTOCOL_VERSION),
241→    id: fc.nat(1000),
242→    command: fc.constant("execute" as const),
243→    function: arbIdent,
244→    inputs: fc.array(fc.oneof(fc.integer(), fc.constant("hello"), fc.boolean()), { maxLength: 4 }),
245→    mocks: fc.constant([]),
246→  }) as fc.Arbitrary<ExecuteRequest>,
247→  fc.record({
248→    protocol_version: fc.constant(PROTOCOL_VERSION),
249→    id: fc.nat(1000),
250→    command: fc.constant("shutdown" as const),
251→  }) as fc.Arbitrary<ShutdownRequest>,
252→);
253→
254→const arbResponse: fc.Arbitrary<Response> = fc.oneof(
255→  fc.record({
256→    protocol_version: fc.constant(PROTOCOL_VERSION),
257→    id: fc.nat(1000),
258→    status: fc.constant("handshake" as const),
259→    frontend_version: fc.constant(PROTOCOL_VERSION),
260→    language: fc.constant("typescript"),
261→    capabilities: fc.array(arbIdent, { maxLength: 3 }),
262→  }) as fc.Arbitrary<HandshakeResponse>,
263→  fc.record({
264→    protocol_version: fc.constant(PROTOCOL_VERSION),
265→    id: fc.nat(1000),
266→    status: fc.constant("analyze" as const),
267→    functions: fc.array(arbFunctionAnalysis, { maxLength: 3 }),
268→  }) as fc.Arbitrary<AnalyzeResponse>,
269→  fc.record({
270→    protocol_version: fc.constant(PROTOCOL_VERSION),
271→    id: fc.nat(1000),
272→    status: fc.constant("error" as const),
273→    code: arbErrorCode,
274→    message: arbShortString,
275→  }) as fc.Arbitrary<ErrorResponse>,
276→);
277→
278→// ---------------------------------------------------------------------------
279→// Tests
280→// ---------------------------------------------------------------------------
281→
282→describe("property: protocol message round-trips", () => {
283→  it("Request survives JSON round-trip", () => {
284→    fc.assert(
285→      fc.property(arbRequest, (req) => {
286→        const json = JSON.stringify(req);
287→        const decoded = JSON.parse(json) as Request;
288→        expect(decoded).toEqual(req);
289→      }),
290→    );
291→  });
292→
293→  it("Response survives JSON round-trip", () => {
294→    fc.assert(
295→      fc.property(arbResponse, (resp) => {
296→        const json = JSON.stringify(resp);
297→        const decoded = JSON.parse(json) as Response;
298→        expect(decoded).toEqual(resp);
299→      }),
300→    );
301→  });
302→});
303→
304→describe("property: SymExpr structural validity", () => {
305→  const VALID_KINDS = new Set(["param", "const", "bin_op", "un_op", "call", "unknown"]);
306→
307→  it("every generated SymExpr has a valid kind tag", () => {
308→    fc.assert(
309→      fc.property(arbSymExpr, (expr) => {
310→        expect(VALID_KINDS.has(expr.kind)).toBe(true);
311→      }),
312→    );
313→  });
314→
315→  it("bin_op always has left, right, and op", () => {
316→    fc.assert(
317→      fc.property(arbSymExpr, (expr) => {
318→        if (expr.kind === "bin_op") {
319→          expect(expr.left).toBeDefined();
320→          expect(expr.right).toBeDefined();
321→          expect(expr.op).toBeDefined();
322→        }
323→      }),
324→    );
325→  });
326→
327→  it("un_op always has operand and op", () => {
328→    fc.assert(
329→      fc.property(arbSymExpr, (expr) => {
330→        if (expr.kind === "un_op") {
331→          expect(expr.operand).toBeDefined();
332→          expect(expr.op).toBeDefined();
333→        }
334→      }),
335→    );
336→  });
337→
338→  it("param always has name and path", () => {
339→    fc.assert(
340→      fc.property(arbSymExpr, (expr) => {
341→        if (expr.kind === "param") {
342→          expect(typeof expr.name).toBe("string");
343→          expect(Array.isArray(expr.path)).toBe(true);
344→        }
345→      }),
346→    );
347→  });
348→
349→  it("SymExpr round-trips through JSON", () => {
350→    fc.assert(
351→      fc.property(arbSymExpr, (expr) => {
352→        const json = JSON.stringify(expr);
353→        const decoded = JSON.parse(json) as SymExpr;
354→        expect(decoded).toEqual(expr);
355→      }),
356→    );
357→  });
358→});
359→
360→describe("property: TypeInfo structural validity", () => {
361→  const VALID_KINDS = new Set([
362→    "int", "float", "str", "bool", "unknown", "opaque",
363→    "array", "object", "union", "nullable", "complex",
364→  ]);
365→
366→  it("every generated TypeInfo has a valid kind tag", () => {
367→    fc.assert(
368→      fc.property(arbTypeInfo, (ti) => {
369→        expect(VALID_KINDS.has(ti.kind)).toBe(true);
370→      }),
371→    );
372→  });
373→
374→  it("TypeInfo round-trips through JSON", () => {
375→    fc.assert(
376→      fc.property(arbTypeInfo, (ti) => {
377→        const json = JSON.stringify(ti);
378→        const decoded = JSON.parse(json) as TypeInfo;
379→        expect(decoded).toEqual(ti);
380→      }),
381→    );
382→  });
383→});
384→
385→describe("property: BranchDecision round-trips", () => {
386→  it("BranchDecision survives JSON round-trip", () => {
387→    fc.assert(
388→      fc.property(arbBranchDecision, (bd) => {
389→        const json = JSON.stringify(bd);
390→        const decoded = JSON.parse(json) as BranchDecision;
391→        expect(decoded).toEqual(bd);
392→      }),
393→    );
394→  });
395→});
396→
397→describe("property: TraceEvent round-trips", () => {
398→  it("TraceEvent survives JSON round-trip", () => {
399→    fc.assert(
400→      fc.property(arbTraceEvent, (te) => {
401→        const json = JSON.stringify(te);
402→        const decoded = JSON.parse(json) as TraceEvent;
403→        expect(decoded).toEqual(te);
404→      }),
405→    );
406→  });
407→});
408→
409→// ---------------------------------------------------------------------------
410→// SymExpr builder parity tests
411→// ---------------------------------------------------------------------------
412→
413→/**
414→ * Parse a TS expression string and extract the expression AST node.
415→ * Wraps the expression in `const __expr = EXPR;` so the compiler parses it.
416→ */
417→function parseExpr(exprSource: string): ts.Expression {
418→  const source = `const __expr = ${exprSource};`;
419→  const sf = ts.createSourceFile("test.ts", source, ts.ScriptTarget.ESNext, true);
420→  const stmt = sf.statements[0] as ts.VariableStatement;
421→  const decl = stmt.declarationList.declarations[0]!;
422→  return decl.initializer!;
423→}
424→
425→/**
426→ * Check if a SymExpr tree contains at least one non-unknown leaf.
427→ * When all leaves are unknown, buildSymExprWithFlow intentionally returns
428→ * unknown as an optimization — this is not a parity violation.
429→ */
430→function hasNonUnknownLeaf(expr: SymExpr): boolean {
431→  if (expr.kind === "param" || expr.kind === "const") return true;
432→  if (expr.kind === "bin_op") return hasNonUnknownLeaf(expr.left) || hasNonUnknownLeaf(expr.right);
433→  if (expr.kind === "un_op") return hasNonUnknownLeaf(expr.operand);
434→  if (expr.kind === "call") {
435→    const recOk = expr.receiver ? hasNonUnknownLeaf(expr.receiver) : false;
436→    return recOk || expr.args.some(hasNonUnknownLeaf);
437→  }
438→  return false;
439→}
440→
441→const PARAM_NAME = "x";
442→const paramNames = new Set([PARAM_NAME]);
443→const resolveName = (name: string): SymExpr | undefined =>
444→  name === PARAM_NAME ? { kind: "param", name: PARAM_NAME, path: [] } : undefined;
445→
446→/** Generator for binary operator source tokens that binaryTokenToOp handles. */
447→const arbBinOp = fc.constantFrom(
448→  "===", "!==", "==", "!=",
449→  "<", "<=", ">", ">=",
450→  "+", "-", "*", "/", "%",
451→  "&&", "||",
452→  "&", "|", "^",
453→);
454→
455→/** Generator for unary prefix operator source tokens. */
456→const arbUnOp = fc.constantFrom("!", "-", "~");
457→
458→/**
459→ * Generator for TypeScript expression source code involving param `x`.
460→ * Each generated expression should be parseable and involve the param
461→ * so at least one builder returns a non-unknown result.
462→ */
463→const arbExprSource: fc.Arbitrary<string> = fc.letrec<{ expr: string }>(tie => ({
464→  expr: fc.oneof(
465→    { depthIdentifier: "exprdepth", maxDepth: 2 },
466→    // Param identifier
467→    fc.constant(PARAM_NAME),
468→    // Numeric literals
469→    fc.integer({ min: -1000, max: 1000 }).map(n => String(n < 0 ? `(${n})` : n)),
470→    // String literals
471→    fc.stringMatching(/^[a-z]{0,5}$/).map(s => `"${s}"`),
472→    // Boolean literals
473→    fc.boolean().map(b => String(b)),
474→    // null
475→    fc.constant("null"),
476→    // Property access on param
477→    fc.stringMatching(/^[a-z]{1,5}$/).map(prop => `${PARAM_NAME}.${prop}`),
478→    // Binary expression with param
479→    arbBinOp.chain(op =>
480→      tie("expr").map(right => `(${PARAM_NAME} ${op} ${right})`),
481→    ),
482→    // Unary prefix
483→    arbUnOp.map(op => `(${op}${PARAM_NAME})`),
484→    // typeof
485→    fc.constant(`(typeof ${PARAM_NAME})`),
486→    // Method call on param
487→    fc.stringMatching(/^[a-z]{1,5}$/).map(m => `${PARAM_NAME}.${m}()`),
488→    // Method call with argument
489→    fc.tuple(
490→      fc.stringMatching(/^[a-z]{1,5}$/),
491→      fc.stringMatching(/^[a-z]{0,3}$/),
492→    ).map(([m, arg]) => `${PARAM_NAME}.${m}("${arg}")`),
493→    // Free function call with param arg
494→    fc.stringMatching(/^[a-z]{1,5}$/).map(fn => `${fn}(${PARAM_NAME})`),
495→  ),
496→})).expr;
497→
498→describe("property: buildSymExpr / buildSymExprWithFlow parity", () => {
499→  it("both builders handle param-involving expressions consistently", () => {
500→    fc.assert(
501→      fc.property(arbExprSource, (source) => {
502→        let node: ts.Expression;
503→        try {
504→          node = parseExpr(source);
505→        } catch {
506→          return; // skip unparseable expressions
507→        }
508→
509→        const fromBuildSymExpr = buildSymExpr(node, paramNames);
510→        const fromBuildWithFlow = buildSymExprWithFlow(node, resolveName);
511→
512→        const exprResult = fromBuildSymExpr.kind !== "unknown";
513→        const flowResult = fromBuildWithFlow.kind !== "unknown";
514→
515→        // If buildSymExpr returns non-unknown, buildSymExprWithFlow should too
516→        // UNLESS the result has no non-unknown leaves (the "all-unknown
517→        // optimization" in buildSymExprWithFlow is intentional).
518→        if (exprResult && !flowResult) {
519→          expect(hasNonUnknownLeaf(fromBuildSymExpr)).toBe(false);
520→        }
521→
522→        // If buildSymExprWithFlow returns non-unknown, buildSymExpr must too.
523→        // There is no case where flow handles something that expr doesn't.
524→        if (flowResult) {
525→          expect(exprResult).toBe(true);
526→        }
527→      }),
528→      { numRuns: 500 },
529→    );
530→  });
531→
532→  it("individual AST node types are handled by both builders", () => {
533→    // Fixed test cases for each AST node type — these are deterministic
534→    // regression anchors complementing the random property above.
535→    const cases: Array<{ label: string; source: string }> = [
536→      { label: "Identifier (param)", source: "x" },
537→      { label: "NumericLiteral (int)", source: "42" },
538→      { label: "NumericLiteral (float)", source: "3.14" },
539→      { label: "StringLiteral", source: '"hello"' },
540→      { label: "TrueKeyword", source: "true" },
541→      { label: "FalseKeyword", source: "false" },
542→      { label: "NullKeyword", source: "null" },
543→      { label: "BinaryExpression (eq)", source: "x === 1" },
544→      { label: "BinaryExpression (add)", source: "x + 1" },
545→      { label: "BinaryExpression (and)", source: "x && true" },
546→      { label: "PrefixUnaryExpression (not)", source: "!x" },
547→      { label: "PrefixUnaryExpression (neg)", source: "-x" },
548→      { label: "PrefixUnaryExpression (bitwise_not)", source: "~x" },
549→      { label: "PropertyAccessExpression", source: "x.length" },
550→      { label: "TypeOfExpression", source: "typeof x" },
551→      { label: "CallExpression (method)", source: 'x.indexOf("a")' },
552→      { label: "CallExpression (method no args)", source: "x.trim()" },
553→      { label: "CallExpression (free fn)", source: "parseInt(x)" },
554→      { label: "ParenthesizedExpression", source: "(x)" },
555→    ];
556→
557→    for (const { label, source } of cases) {
558→      const node = parseExpr(source);
559→      const fromExpr = buildSymExpr(node, paramNames);
560→      const fromFlow = buildSymExprWithFlow(node, resolveName);
561→
562→      // Both must return non-unknown for param-involving expressions
563→      if (fromExpr.kind === "unknown") {
564→        throw new Error(`buildSymExpr returned unknown for ${label}: ${source}`);
565→      }
566→      if (fromFlow.kind === "unknown") {
567→        throw new Error(`buildSymExprWithFlow returned unknown for ${label}: ${source}`);
568→      }
569→    }
570→  });
571→
572→  it("both builders return unknown for non-param identifiers", () => {
573→    const node = parseExpr("unknownVar");
574→    const fromExpr = buildSymExpr(node, paramNames);
575→    const fromFlow = buildSymExprWithFlow(node, resolveName);
576→
577→    expect(fromExpr.kind).toBe("unknown");
578→    expect(fromFlow.kind).toBe("unknown");
579→  });
580→
581→  it("nested expressions maintain parity", () => {
582→    const nestedCases = [
583→      'x.length > 0',
584→      'x.indexOf("@") !== -1',
585→      'typeof x === "string"',
586→      '!(x > 0)',
587→      'x + 1 > 0',
588→    ];
589→
590→    for (const source of nestedCases) {
591→      const node = parseExpr(source);
592→      const fromExpr = buildSymExpr(node, paramNames);
593→      const fromFlow = buildSymExprWithFlow(node, resolveName);
594→
595→      if (fromExpr.kind === "unknown") {
596→        throw new Error(`buildSymExpr returned unknown for: ${source}`);
597→      }
598→      if (fromFlow.kind === "unknown") {
599→        throw new Error(`buildSymExprWithFlow returned unknown for: ${source}`);
600→      }
601→    }
602→  });
603→});
