 58→  function: string;
 59→  mocks: MockConfig[];
 60→  project_root?: string | null;
 61→}
 62→
 63→export interface ExecuteRequest extends BaseRequest {
 64→  command: "execute";
 65→  function: string;
 66→  inputs: unknown[];
 67→  mocks: MockConfig[];
 68→  setup_context?: unknown;
 69→}
 70→
 71→export interface SetupRequest extends BaseRequest {
 72→  command: "setup";
 73→  file: string;
 74→  function: string;
 75→  mode: SetupMode;
 76→  project_root?: string | null;
 77→}
 78→
 79→export interface TeardownRequest extends BaseRequest {
 80→  command: "teardown";
 81→  function: string;
 82→}
 83→
 84→export interface GenerateRequest extends BaseRequest {
 85→  command: "generate";
 86→  file: string;
 87→  name: string;
 88→  kind: GeneratorKind;
 89→  recipe?: unknown;
 90→  project_root?: string | null;
 91→}
 92→
 93→export interface ShutdownRequest extends BaseRequest {
 94→  command: "shutdown";
 95→}
 96→
 97→export type Request =
 98→  | HandshakeRequest
 99→  | AnalyzeRequest
100→  | InstrumentRequest
101→  | ExecuteRequest
102→  | SetupRequest
103→  | TeardownRequest
104→  | GenerateRequest
105→  | ShutdownRequest;
106→
107→// ---------------------------------------------------------------------------
108→// Response: Frontend → Core
109→// ---------------------------------------------------------------------------
110→
111→export type ResponseStatus =
112→  | "handshake"
113→  | "analyze"
114→  | "instrument"
115→  | "execute"
116→  | "setup"
117→  | "teardown_ack"
118→  | "generate"
119→  | "shutdown_ack"
120→  | "error";
