122→export type ErrorCode =
123→  | "file_not_found"
124→  | "function_not_found"
125→  | "parse_error"
126→  | "instrumentation_failed"
127→  | "execution_timeout"
128→  | "execution_crash"
129→  | "version_mismatch"
130→  | "invalid_request"
131→  | "internal_error";
132→
133→interface BaseResponse {
134→  protocol_version: string;
135→  id: number;
136→  status: ResponseStatus;
137→}
138→
139→export interface HandshakeResponse extends BaseResponse {
140→  status: "handshake";
141→  frontend_version: string;
