225→  direction: "encrypt" | "decrypt" | "both";
226→  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
227→  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
