314→  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
315→  | "add" | "sub" | "mul" | "div" | "mod"
316→  | "and" | "or"
317→  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
318→  | "in" | "instance_of";
