375→    protocol_version: PROTOCOL_VERSION,
376→    id,
377→    status: "error",
378→    code,
379→    message,
380→  };
381→}
382→
383→/**
384→ * Parse a JSON string into a Request, returning an error response if invalid.
385→ */
386→export function parseRequest(line: string): { request: Request } | { error: ErrorResponse } {
387→  let parsed: unknown;
388→  try {
389→    parsed = JSON.parse(line);
390→  } catch {
391→    return {
392→      error: errorResponse(0, "invalid_request", `Invalid JSON: ${line.slice(0, 100)}`),
393→    };
394→  }
395→
396→  if (typeof parsed !== "object" || parsed === null) {
397→    return {
398→      error: errorResponse(0, "invalid_request", "Request must be a JSON object"),
399→    };
400→  }
401→
402→  const obj = parsed as Record<string, unknown>;
403→
404→  if (typeof obj["id"] !== "number") {
405→    return {
406→      error: errorResponse(0, "invalid_request", "Request must have a numeric 'id' field"),
407→    };
408→  }
409→
410→  const id = obj["id"] as number;
411→
412→  if (typeof obj["protocol_version"] !== "string") {
413→    return {
414→      error: errorResponse(id, "invalid_request", "Request must have a 'protocol_version' string field"),
415→    };
416→  }
417→
418→  if (typeof obj["command"] !== "string") {
419→    return {
420→      error: errorResponse(id, "invalid_request", "Request must have a 'command' string field"),
421→    };
422→  }
423→
424→  const validCommands = ["handshake", "analyze", "instrument", "execute", "setup", "teardown", "generate", "shutdown"];
425→  if (!validCommands.includes(obj["command"] as string)) {
426→    return {
427→      error: errorResponse(id, "invalid_request", `Unknown command: ${String(obj["command"])}`),
428→    };
429→  }
430→
431→  return { request: parsed as Request };
432→}
433→
434→/**
435→ * Clear stored instrumented sources and setup state. Useful for testing.
436→ */
437→export function clearInstrumentedSources(): void {
438→  instrumentedSources.clear();
439→  loadedSetupModules.clear();
440→  setupContexts.clear();
441→}
442→
443→/** Number of cached instrumented sources. Exposed for testing. */
444→export function instrumentedSourcesSize(): number {
445→  return instrumentedSources.size;
446→}
