/**
 * Protocol types for communication between the Rust core and TypeScript frontend.
 *
 * All messages are newline-delimited JSON over stdin/stdout. The core sends
 * Request messages and receives Response messages back. Every message includes
 * a protocol version for compatibility checking.
 */

export const PROTOCOL_VERSION = "0.1.0";
export const FRONTEND_LANGUAGE = "typescript";

// ---------------------------------------------------------------------------
// Request: Core → Frontend
// ---------------------------------------------------------------------------

export type SetupMode = "per_function" | "per_execution";

export type SetupLevel = "session" | "file" | "function" | "execution";

export interface SetupContextEntry {
  level: SetupLevel;
  context: unknown;
}

export interface SetupContextStack {
  contexts: SetupContextEntry[];
}

export type GeneratorKind = "type_name" | "param_name";

export type Command =
  | "handshake"
  | "analyze"
  | "instrument"
  | "execute"
  | "setup"
  | "teardown"
  | "generate"
  | "shutdown";

export interface MockConfig {
  symbol: string;
  return_values: unknown[];
  should_track_calls: boolean;
  default_behavior: "return_generated" | "repeat_last" | "throw_error" | "passthrough";
}

interface BaseRequest {
  protocol_version: string;
  id: number;
  command: Command;
}

export interface HandshakeRequest extends BaseRequest {
  command: "handshake";
  capabilities: string[];
}

export interface AnalyzeRequest extends BaseRequest {
  command: "analyze";
  file: string;
  function?: string | null;
  project_root?: string | null;
}

export interface InstrumentRequest extends BaseRequest {
  command: "instrument";
  file: string;
  function: string;
  mocks: MockConfig[];
  project_root?: string | null;
}

export interface ExecuteRequest extends BaseRequest {
  command: "execute";
  function: string;
  inputs: unknown[];
  mocks: MockConfig[];
  setup_context?: SetupContextStack | null;
}

export interface SetupRequest extends BaseRequest {
  command: "setup";
  file: string;
  scope: string;
  level: SetupLevel;
  project_root?: string | null;
  parent_context?: SetupContextStack | null;
}

export interface TeardownRequest extends BaseRequest {
  command: "teardown";
  scope: string;
  level: SetupLevel;
}

export interface GenerateRequest extends BaseRequest {
  command: "generate";
  file: string;
  name: string;
  kind: GeneratorKind;
  recipe?: unknown;
  project_root?: string | null;
}

export interface ShutdownRequest extends BaseRequest {
  command: "shutdown";
}

export type Request =
  | HandshakeRequest
  | AnalyzeRequest
  | InstrumentRequest
  | ExecuteRequest
  | SetupRequest
  | TeardownRequest
  | GenerateRequest
  | ShutdownRequest;

// ---------------------------------------------------------------------------
// Response: Frontend → Core
// ---------------------------------------------------------------------------

export type ResponseStatus =
  | "handshake"
  | "analyze"
  | "instrument"
  | "execute"
  | "setup"
  | "teardown_ack"
  | "generate"
  | "shutdown_ack"
  | "error";

export type ErrorCode =
  | "file_not_found"
  | "function_not_found"
  | "parse_error"
  | "instrumentation_failed"
  | "execution_timeout"
  | "execution_crash"
  | "version_mismatch"
  | "invalid_request"
  | "internal_error";

interface BaseResponse {
  protocol_version: string;
  id: number;
  status: ResponseStatus;
}

export interface HandshakeResponse extends BaseResponse {
  status: "handshake";
  frontend_version: string;
  language: string;
  capabilities: string[];
}

export interface AnalyzeResponse extends BaseResponse {
  status: "analyze";
  functions: FunctionAnalysis[];
}

export interface InstrumentResponse extends BaseResponse {
  status: "instrument";
  instrumented: boolean;
  output_file: string | null;
  instrumentable_line_count?: number;
}

export interface ExecuteResponse extends BaseResponse {
  status: "execute";
  return_value: unknown;
  thrown_error: ErrorInfo | null;
  branch_path: BranchDecision[];
  lines_executed: number[];
  calls_to_external: ExternalCall[];
  path_constraints: SymConstraint[];
  side_effects: SideEffect[];
  performance: PerformanceMetrics;
  capture_truncation?: TruncationInfo;
  scope_events?: TraceEvent[];
}

export interface SetupResponse extends BaseResponse {
  status: "setup";
  setup_context: unknown;
}

export interface TeardownAckResponse extends BaseResponse {
  status: "teardown_ack";
}

export interface GenerateResponse extends BaseResponse {
  status: "generate";
  value: unknown;
  generator_id: string;
  recipe?: unknown;
}

export interface ShutdownAckResponse extends BaseResponse {
  status: "shutdown_ack";
}

export interface ErrorResponse extends BaseResponse {
  status: "error";
  code: ErrorCode;
  message: string;
  details?: unknown;
}

export type Response =
  | HandshakeResponse
  | AnalyzeResponse
  | InstrumentResponse
  | ExecuteResponse
  | SetupResponse
  | TeardownAckResponse
  | GenerateResponse
  | ShutdownAckResponse
  | ErrorResponse;

// ---------------------------------------------------------------------------
// Supporting types
// ---------------------------------------------------------------------------

/** A literal constant extracted from source code for use as a candidate test input. */
export type LiteralValue =
  | { type: "int"; value: number }
  | { type: "float"; value: number }
  | { type: "str"; value: string }
  | { type: "bool"; value: boolean }
  | { type: "regex"; pattern: string };

export interface CryptoBoundary {
  symbol: string;
  source_module: string;
  direction: "encrypt" | "decrypt" | "both";
  output: "ciphertext" | "plaintext" | "key" | "hash" | "signature" | "verified";
  param_roles: Record<string, "key" | "data" | "iv" | "nonce" | "tag" | "aad" | "algorithm">;
  call_sites: number[];
}

export interface FunctionAnalysis {
  name: string;
  exported?: boolean;
  params: ParamInfo[];
  branches: BranchInfo[];
  dependencies: ExternalDependency[];
  return_type: TypeInfo;
  start_line: number;
  end_line: number;
  literals?: LiteralValue[];
  crypto_boundaries?: CryptoBoundary[];
}

export interface ParamInfo {
  name: string;
  type: TypeInfo;
  type_name?: string;
}

/** Well-known complex types beyond primitives and structural types. */
export type ComplexKind =
  | "date" | "date_time" | "time" | "duration"
  | "reg_exp" | "char" | "symbol"
  | "big_int" | "big_decimal" | "complex" | "rational" | "range"
  | "buffer" | "bit_set"
  | "error" | "option" | "result"
  | "closure" | "iterator"
  | "url" | "ip_address"
  | "uuid"
  | "path"
  | "money" | "sem_ver" | "email" | "mime_type" | "color" | "geo_point" | "locale"
  | "rune" | "go_byte";

export type TypeInfo =
  | { kind: "int" }
  | { kind: "float" }
  | { kind: "str" }
  | { kind: "bool" }
  | { kind: "unknown" }
  | { kind: "array"; element: TypeInfo }
  | { kind: "object"; fields: [string, TypeInfo][] }
  | { kind: "union"; variants: TypeInfo[] }
  | { kind: "nullable"; inner: TypeInfo }
  | { kind: "complex"; complex_kind: ComplexKind; metadata?: Record<string, unknown>; inner?: TypeInfo }
  | { kind: "opaque"; label: string };

export interface BranchInfo {
  id: number;
  line: number;
  condition_text: string;
  condition: SymExpr | null;
  branch_type: BranchType;
}

export type BranchType =
  | "if"
  | "else_if"
  | "switch"
  | "ternary"
  | "logical_and"
  | "logical_or"
  | "while"
  | "for";

export type SymExpr =
  | { kind: "param"; name: string; path: string[] }
  | SymExprConst
  | { kind: "bin_op"; op: BinOpKind; left: SymExpr; right: SymExpr }
  | { kind: "un_op"; op: UnOpKind; operand: SymExpr }
  | { kind: "call"; name: string; receiver: SymExpr | null; args: SymExpr[] }
  | { kind: "unknown" };

/** Const variant of SymExpr. Flattened to match Rust serde serialization. */
export type SymExprConst =
  | { kind: "const"; type: "int"; value: number }
  | { kind: "const"; type: "float"; value: number }
  | { kind: "const"; type: "str"; value: string }
  | { kind: "const"; type: "bool"; value: boolean }
  | { kind: "const"; type: "null" }
  | { kind: "const"; type: "undefined" }
  | { kind: "const"; type: "complex"; value: { kind: ComplexKind; repr: SymExprConst } };

export type BinOpKind =
  | "eq" | "ne" | "lt" | "le" | "gt" | "ge"
  | "add" | "sub" | "mul" | "div" | "mod"
  | "and" | "or"
  | "bitwise_and" | "bitwise_or" | "bitwise_xor"
  | "in" | "instance_of";

export type UnOpKind = "not" | "neg" | "bitwise_not" | "typeof";

export interface BranchDecision {
  branch_id: number;
  line: number;
  taken: boolean;
  constraint: SymConstraint;
}

export type ScopeEvent =
  | { kind: "loop_enter"; loop_id: number }
  | { kind: "loop_exit"; loop_id: number }
  | { kind: "call_enter"; call_site_id: number }
  | { kind: "call_exit"; call_site_id: number };

export type TraceEvent =
  | { type: "branch"; decision: BranchDecision }
  | { type: "scope"; event: ScopeEvent };

export type SymConstraint =
  | { kind: "expr"; expr: SymExpr }
  | { kind: "unknown"; hint: string };

export interface ExternalCall {
  symbol: string;
  args: unknown[];
  return_value: unknown;
}

export interface ExternalDependency {
  kind: DependencyKind;
  symbol: string;
  source_module: string;
  return_type: TypeInfo;
  param_types: TypeInfo[];
  call_sites: number[];
}

export type DependencyKind =
  | "function_call"
  | "method_call"
  | "property_access"
  | "module_import";

export type SideEffect =
  | { kind: "console_output"; level: string; message: string }
  | { kind: "file_write"; path: string; content: string }
  | { kind: "network_request"; method: string; url: string; body: unknown }
  | { kind: "environment_read"; variable: string; value: string | null }
  | { kind: "global_mutation"; name: string }
  | { kind: "thrown_error"; error_type: string; message: string; stack: string | null }
  | { kind: "global_state_change"; variable: string; before: unknown; after: unknown };

export type ErrorCategory = "validation" | "runtime" | "infrastructure" | "unknown";

export interface ErrorInfo {
  error_type: string;
  message: string;
  stack: string | null;
  error_category?: ErrorCategory;
}

export interface TruncationInfo {
  was_truncated: boolean;
  original_lines: number;
  original_bytes: number;
}

export interface PerformanceMetrics {
  wall_time_ms: number;
  cpu_time_us: number;
  heap_used_bytes: number;
  heap_allocated_bytes: number;
}

/**
 * Setup and generator module loader for the Shatter TypeScript frontend.
 *
 * Loads user-provided setup/teardown and generator files using the same
 * vm.createContext + TypeScript transpile pattern as executor.ts.
 */

import * as ts from "typescript";
import * as fs from "node:fs";
import * as vm from "node:vm";
import * as path from "node:path";
import { createRequire } from "node:module";
import type { SetupLevel, SetupContextStack, GeneratorKind } from "./protocol.js";

/** Default setup timeout in milliseconds (30 seconds). */
const DEFAULT_SETUP_TIMEOUT_MS = 30_000;

/**
 * Read SHATTER_SETUP_TIMEOUT env var (seconds) and return milliseconds.
 * Default: 30s. Ignores non-positive or non-numeric values.
 */
export function getSetupTimeoutMs(): number {
  const raw = process.env["SHATTER_SETUP_TIMEOUT"];
  if (raw !== undefined) {
    const secs = parseFloat(raw);
    if (Number.isFinite(secs) && secs > 0) {
      return secs * 1000;
    }
  }
  return DEFAULT_SETUP_TIMEOUT_MS;
}

/** A loaded setup module with its exports available for calling. */
export interface SetupModule {
  exports: Record<string, unknown>;
  filePath: string;
}

/** A loaded generator module with its exports available for calling. */
export interface GeneratorModule {
  exports: Record<string, unknown>;
  filePath: string;
}

/**
 * Transpile and load a TypeScript/JavaScript file, returning its exports.
 */
function loadAndTranspile(filePath: string): Record<string, unknown> {
  const absolutePath = path.resolve(filePath);
  const source = fs.readFileSync(absolutePath, "utf-8");
  const result = ts.transpileModule(source, {
    compilerOptions: {
      target: ts.ScriptTarget.ES2022,
      module: ts.ModuleKind.CommonJS,
      esModuleInterop: true,
      strict: true,
      jsx: ts.JsxEmit.ReactJSX,
    },
    fileName: absolutePath,
  });

  const targetRequire = createRequire(absolutePath);
  const moduleExports: Record<string, unknown> = {};
  const moduleObj = { exports: moduleExports };

  const sandbox = vm.createContext({
    module: moduleObj,
    exports: moduleExports,
    require: targetRequire,
    console,
    process,
    Buffer,
    setTimeout,
    clearTimeout,
    setInterval,
    clearInterval,
    __filename: absolutePath,
    __dirname: path.dirname(absolutePath),
  });

  vm.runInContext(result.outputText, sandbox, { filename: absolutePath });

  const finalExports = (sandbox as Record<string, unknown>)["module"] as {
    exports: Record<string, unknown>;
  };
  return finalExports.exports;
}

/**
 * Load a setup module file. The file should export a `setup()` function
 * and optionally a `teardown()` function.
 */
export function loadSetupModule(file: string): SetupModule {
  const exports = loadAndTranspile(file);
  return { exports, filePath: path.resolve(file) };
}

/**
 * Run the setup() export from a loaded setup module.
 *
 * Calls `module.setup(scope, parentContext?)` and returns the setup_context.
 * Supports both sync and async setup functions. Applies SHATTER_SETUP_TIMEOUT.
 */
export async function runSetup(
  setupModule: SetupModule,
  scope: string,
  _level: SetupLevel,
  parentContext?: SetupContextStack | null,
): Promise<unknown> {
  const setupFn = setupModule.exports["setup"];
  if (typeof setupFn !== "function") {
    throw new Error(
      `Setup file "${setupModule.filePath}" does not export a setup() function. ` +
      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
    );
  }

  const result = (setupFn as (scope: string, parentContext?: SetupContextStack | null) => unknown)(
    scope,
    parentContext ?? null,
  );

  // Handle async setup functions
  if (result != null && typeof (result as PromiseLike<unknown>).then === "function") {
    const timeoutMs = getSetupTimeoutMs();
    return Promise.race([
      result as Promise<unknown>,
      new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error(`Setup timed out after ${timeoutMs}ms`)), timeoutMs),
      ),
    ]);
  }

  return result;
}

/**
 * Run the teardown() export from a loaded setup module.
 *
 * Calls `module.teardown(scope, setupContext)`. Supports async teardown.
 */
export async function runTeardown(
  setupModule: SetupModule,
  scope: string,
  setupContext: unknown,
): Promise<void> {
  const teardownFn = setupModule.exports["teardown"];
  if (typeof teardownFn !== "function") {
    throw new Error(
      `Setup file "${setupModule.filePath}" does not export a teardown() function. ` +
      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
    );
  }
  const result = (teardownFn as (scope: string, ctx: unknown) => unknown)(scope, setupContext);

  // Handle async teardown functions
  if (result != null && typeof (result as PromiseLike<unknown>).then === "function") {
    const timeoutMs = getSetupTimeoutMs();
    await Promise.race([
      result as Promise<unknown>,
      new Promise<never>((_, reject) =>
        setTimeout(() => reject(new Error(`Teardown timed out after ${timeoutMs}ms`)), timeoutMs),
      ),
    ]);
  }
}

/**
 * Load a generator module file. The file should export named functions
 * that produce values when called.
 */
export function loadGeneratorModule(file: string): GeneratorModule {
  const exports = loadAndTranspile(file);
  return { exports, filePath: path.resolve(file) };
}

/**
 * Run a named generator function from a loaded generator module.
 *
 * For `kind: "type_name"`, `name` is the type name (e.g. "User").
 * For `kind: "param_name"`, `name` is the parameter name (e.g. "authToken").
 *
 * The module should export a function with that name.
 */
export function runGenerator(
  generatorModule: GeneratorModule,
  name: string,
  kind: GeneratorKind,
): unknown {
  const genFn = generatorModule.exports[name];
  if (typeof genFn !== "function") {
    throw new Error(
      `Generator file "${generatorModule.filePath}" does not export a "${name}" function ` +
      `(kind: ${kind}). Available exports: ${Object.keys(generatorModule.exports).join(", ")}`,
    );
  }
  return (genFn as () => unknown)();
}

/**
 * Command handlers for the Shatter protocol.
 *
 * Each handler receives a typed request and returns a typed response.
 * The instrument handler stores instrumented source in memory so the
 * execute handler can use it for branch-recording execution.
 */

import * as fs from "node:fs";
import * as path from "node:path";
import {
  PROTOCOL_VERSION,
  FRONTEND_LANGUAGE,
  type Request,
  type Response,
  type ErrorResponse,
} from "./protocol.js";
import { analyzeFile } from "./analyzer.js";
import { instrumentFunction } from "./instrumentor.js";
import {
  executeFunction,
  executeInstrumented,
  buildExecuteResponse,
  setProjectRoot,
  clearModuleCache,
} from "./executor.js";
import {
  loadSetupModule,
  runSetup,
  runTeardown,
  loadGeneratorModule,
  runGenerator,
  type SetupModule,
} from "./setup-loader.js";
import {
  loadWasmPlugin,
  runWasmGenerator,
  clearWasmCache,
} from "./wasm-generator.js";

/** Supported capabilities for this frontend. */
const SUPPORTED_CAPABILITIES = [
  "analyze", "execute", "instrument", "setup", "generate",
  "complex_type:date", "complex_type:date_time", "complex_type:duration",
  "complex_type:reg_exp", "complex_type:url", "complex_type:big_int",
  "complex_type:buffer", "complex_type:error", "complex_type:symbol",
];

/** Track the last analyzed file so execute can resolve function references. */
let lastAnalyzedFile: string | null = null;

/**
 * Stored instrumented sources, keyed by "file:function".
 * Set by the instrument handler, consumed by the execute handler.
 */
const instrumentedSources = new Map<string, string>();

/**
 * Loaded setup modules, keyed by file path.
 * Cached so teardown can use the same module instance as setup.
 */
const loadedSetupModules = new Map<string, SetupModule>();

/**
 * Setup contexts keyed by "level:scope" (e.g. "function:myFunc", "session:main").
 * Separate keys per level ensure that session-, file-, function-, and
 * execution-level contexts coexist without collision.
 */
const setupContexts = new Map<string, { module: SetupModule; context: unknown }>();

/** Build a cache key for setup/teardown context storage. */
function setupContextKey(level: string, scope: string): string {
  return `${level}:${scope}`;
}

/**
 * Dispatch a parsed request to the appropriate handler.
 *
 * Returns a Response and a shutdown flag. The handler is async because
 * WASM generator loading requires awaiting plugin creation.
 */
export async function handleRequest(request: Request): Promise<{ response: Response; shutdown: boolean }> {
  if (!isVersionCompatible(request.protocol_version)) {
    return {
      response: errorResponse(request.id, "version_mismatch",
        `Unsupported protocol version: ${request.protocol_version} (expected ${PROTOCOL_VERSION})`),
      shutdown: false,
    };
  }

  switch (request.command) {
    case "handshake":
      return {
        response: {
          protocol_version: PROTOCOL_VERSION,
          id: request.id,
          status: "handshake",
          frontend_version: PROTOCOL_VERSION,
          language: FRONTEND_LANGUAGE,
          capabilities: SUPPORTED_CAPABILITIES,
        },
        shutdown: false,
      };

    case "analyze": {
      if (!fs.existsSync(request.file)) {
        return {
          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
          shutdown: false,
        };
      }

      lastAnalyzedFile = path.resolve(request.file);
      setProjectRoot(request.project_root);
      const functions = analyzeFile(request.file, request.function, request.project_root);

      if (request.function != null && functions.length === 0) {
        return {
          response: errorResponse(
            request.id,
            "function_not_found",
            `Function not found: ${request.function} in ${request.file}`,
          ),
          shutdown: false,
        };
      }

      return {
        response: {
          protocol_version: PROTOCOL_VERSION,
          id: request.id,
          status: "analyze",
          functions,
        },
        shutdown: false,
      };
    }

    case "instrument": {
      if (!fs.existsSync(request.file)) {
        return {
          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
          shutdown: false,
        };
      }

      const source = fs.readFileSync(request.file, "utf-8");
      const result = instrumentFunction(source, request.function, request.file);

      if ("error" in result) {
        return {
          response: errorResponse(request.id, "instrumentation_failed", result.error),
          shutdown: false,
        };
      }

      // Store the instrumented source for use by the execute handler.
      // Use resolved path so keys match execute's resolved fileForExec.
      const key = `${path.resolve(request.file)}:${request.function}`;
      instrumentedSources.set(key, result.instrumentedSource);
      lastAnalyzedFile = path.resolve(request.file);

      return {
        response: {
          protocol_version: PROTOCOL_VERSION,
          id: request.id,
          status: "instrument",
          instrumented: true,
          output_file: null,
          instrumentable_line_count: result.instrumentableLineCount,
        },
        shutdown: false,
      };
    }

    case "execute": {
      const funcRef = request.function;
      const fileForExec = resolveFileForExecute(funcRef);

      if (!fileForExec) {
        return {
          response: errorResponse(
            request.id,
            "function_not_found",
            `Cannot resolve file for function: ${funcRef}. Use file:function format.`,
          ),
          shutdown: false,
        };
      }

      try {
        // Check if we have instrumented source for this function
        const funcName = funcRef.includes(":") ? funcRef.split(":").pop()! : funcRef;
        const instrumentKey = `${fileForExec}:${funcName}`;
        const instrumentedSource = instrumentedSources.get(instrumentKey);

        let rawResult;
        if (instrumentedSource) {
          rawResult = await executeInstrumented(instrumentedSource, funcName, request.inputs, request.mocks ?? [], fileForExec);
        } else {
          rawResult = await executeFunction(fileForExec, funcRef, request.inputs);
        }

        return {
          response: buildExecuteResponse(request.id, PROTOCOL_VERSION, rawResult),
          shutdown: false,
        };
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e);
        return {
          response: errorResponse(request.id, "internal_error", `Execute failed: ${msg}`),
          shutdown: false,
        };
      }
    }

    case "setup": {
      if (!fs.existsSync(request.file)) {
        return {
          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
          shutdown: false,
        };
      }

      try {
        let setupModule = loadedSetupModules.get(request.file);
        if (!setupModule) {
          setupModule = loadSetupModule(request.file);
          loadedSetupModules.set(request.file, setupModule);
        }

        const setupContext = await runSetup(
          setupModule, request.scope, request.level, request.parent_context,
        );
        const ctxKey = setupContextKey(request.level, request.scope);
        setupContexts.set(ctxKey, { module: setupModule, context: setupContext });

        return {
          response: {
            protocol_version: PROTOCOL_VERSION,
            id: request.id,
            status: "setup",
            setup_context: setupContext,
          },
          shutdown: false,
        };
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e);
        return {
          response: errorResponse(request.id, "internal_error", `Setup failed: ${msg}`),
          shutdown: false,
        };
      }
    }

    case "teardown": {
      try {
        const ctxKey = setupContextKey(request.level, request.scope);
        const stored = setupContexts.get(ctxKey);
        if (!stored) {
          return {
            response: errorResponse(
              request.id,
              "internal_error",
              `No setup context found for ${request.level}:${request.scope}. Call setup first.`,
            ),
            shutdown: false,
          };
        }

        await runTeardown(stored.module, request.scope, stored.context);
        setupContexts.delete(ctxKey);
        instrumentedSources.clear();
        clearModuleCache();

        return {
          response: {
            protocol_version: PROTOCOL_VERSION,
            id: request.id,
            status: "teardown_ack",
          },
          shutdown: false,
        };
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e);
        return {
          response: errorResponse(request.id, "internal_error", `Teardown failed: ${msg}`),
          shutdown: false,
        };
      }
    }

    case "generate": {
      if (!fs.existsSync(request.file)) {
        return {
          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
          shutdown: false,
        };
      }

      try {
        if (request.file.endsWith(".wasm")) {
          const plugin = await loadWasmPlugin(request.file);
          const result = await runWasmGenerator(plugin, request.name, request.recipe);

          return {
            response: {
              protocol_version: PROTOCOL_VERSION,
              id: request.id,
              status: "generate",
              value: result.value,
              generator_id: result.id,
              ...(result.recipe !== undefined ? { recipe: result.recipe } : {}),
            },
            shutdown: false,
          };
        }

        const generatorModule = loadGeneratorModule(request.file);
        const value = runGenerator(generatorModule, request.name, request.kind);

        return {
          response: {
            protocol_version: PROTOCOL_VERSION,
            id: request.id,
            status: "generate",
            value,
            generator_id: "generated",
          },
          shutdown: false,
        };
      } catch (e: unknown) {
        const msg = e instanceof Error ? e.message : String(e);
        return {
          response: errorResponse(request.id, "internal_error", `Generate failed: ${msg}`),
          shutdown: false,
        };
      }
    }

    case "shutdown":
      await clearWasmCache();
      instrumentedSources.clear();
      clearModuleCache();
      return {
        response: {
          protocol_version: PROTOCOL_VERSION,
          id: request.id,
          status: "shutdown_ack",
        },
        shutdown: true,
      };
  }
}

/**
 * Resolve the file path for an execute request.
 *
 * The function reference can be in "file:function" format or just a function name.
 * If just a name, falls back to the last analyzed file.
 */
function resolveFileForExecute(funcRef: string): string | null {
  if (funcRef.includes(":")) {
    // file:function format — extract the file part
    const lastColon = funcRef.lastIndexOf(":");
    const file = funcRef.substring(0, lastColon);
    if (fs.existsSync(file)) {
      return path.resolve(file);
    }
  }

  // Fall back to last analyzed file (already resolved on store)
  return lastAnalyzedFile;
}

function isVersionCompatible(version: string): boolean {
  // For now, require exact match on major.minor
  const [reqMajor, reqMinor] = version.split(".").map(Number);
  const [ourMajor, ourMinor] = PROTOCOL_VERSION.split(".").map(Number);
  return reqMajor === ourMajor && reqMinor === ourMinor;
}

function errorResponse(id: number, code: ErrorResponse["code"], message: string): ErrorResponse {
  return {
    protocol_version: PROTOCOL_VERSION,
    id,
    status: "error",
    code,
    message,
  };
}

/**
 * Parse a JSON string into a Request, returning an error response if invalid.
 */
export function parseRequest(line: string): { request: Request } | { error: ErrorResponse } {
  let parsed: unknown;
  try {
    parsed = JSON.parse(line);
  } catch {
    return {
      error: errorResponse(0, "invalid_request", `Invalid JSON: ${line.slice(0, 100)}`),
    };
  }

  if (typeof parsed !== "object" || parsed === null) {
    return {
      error: errorResponse(0, "invalid_request", "Request must be a JSON object"),
    };
  }

  const obj = parsed as Record<string, unknown>;

  if (typeof obj["id"] !== "number") {
    return {
      error: errorResponse(0, "invalid_request", "Request must have a numeric 'id' field"),
    };
  }

  const id = obj["id"] as number;

  if (typeof obj["protocol_version"] !== "string") {
    return {
      error: errorResponse(id, "invalid_request", "Request must have a 'protocol_version' string field"),
    };
  }

  if (typeof obj["command"] !== "string") {
    return {
      error: errorResponse(id, "invalid_request", "Request must have a 'command' string field"),
    };
  }

  const validCommands = ["handshake", "analyze", "instrument", "execute", "setup", "teardown", "generate", "shutdown"];
  if (!validCommands.includes(obj["command"] as string)) {
    return {
      error: errorResponse(id, "invalid_request", `Unknown command: ${String(obj["command"])}`),
    };
  }

  return { request: parsed as Request };
}

/**
 * Clear stored instrumented sources and setup state. Useful for testing.
 */
export function clearInstrumentedSources(): void {
  instrumentedSources.clear();
  loadedSetupModules.clear();
  setupContexts.clear();
}

/** Number of cached instrumented sources. Exposed for testing. */
export function instrumentedSourcesSize(): number {
  return instrumentedSources.size;
}

