  1→/**
  2→ * Command handlers for the Shatter protocol.
  3→ *
  4→ * Each handler receives a typed request and returns a typed response.
  5→ * The instrument handler stores instrumented source in memory so the
  6→ * execute handler can use it for branch-recording execution.
  7→ */
  8→
  9→import * as fs from "node:fs";
 10→import * as path from "node:path";
 11→import {
 12→  PROTOCOL_VERSION,
 13→  FRONTEND_LANGUAGE,
 14→  type Request,
 15→  type Response,
 16→  type ErrorResponse,
 17→  type SetupLevel,
 18→} from "./protocol.js";
 19→import { analyzeFile } from "./analyzer.js";
 20→import { instrumentFunction } from "./instrumentor.js";
 21→import {
 22→  executeFunction,
 23→  executeInstrumented,
 24→  buildExecuteResponse,
 25→  setProjectRoot,
 26→  clearModuleCache,
 27→} from "./executor.js";
 28→import {
 29→  loadSetupModule,
 30→  runSetup,
 31→  runTeardown,
 32→  loadGeneratorModule,
 33→  runGenerator,
 34→  type SetupModule,
 35→} from "./setup-loader.js";
 36→import {
 37→  loadWasmPlugin,
 38→  runWasmGenerator,
 39→  clearWasmCache,
 40→} from "./wasm-generator.js";
 41→
 42→/** Supported capabilities for this frontend. */
 43→const SUPPORTED_CAPABILITIES = [
 44→  "analyze", "execute", "instrument", "setup", "generate",
 45→  "complex_type:date", "complex_type:date_time", "complex_type:duration",
 46→  "complex_type:reg_exp", "complex_type:url", "complex_type:big_int",
 47→  "complex_type:buffer", "complex_type:error", "complex_type:symbol",
 48→];
 49→
 50→/** Track the last analyzed file so execute can resolve function references. */
 51→let lastAnalyzedFile: string | null = null;
 52→
 53→/**
 54→ * Stored instrumented sources, keyed by "file:function".
 55→ * Set by the instrument handler, consumed by the execute handler.
 56→ */
 57→const instrumentedSources = new Map<string, string>();
 58→
 59→/**
 60→ * Loaded setup modules, keyed by file path.
 61→ * Cached so teardown can use the same module instance as setup.
 62→ */
 63→const loadedSetupModules = new Map<string, SetupModule>();
 64→
 65→/**
 66→ * Setup contexts from the most recent setup call, keyed by "level:scope"
 67→ * composite key. Separate levels for the same scope are tracked independently.
 68→ */
 69→const setupContexts = new Map<string, { module: SetupModule; context: unknown }>();
 70→
 71→/** Build a composite cache key for the setup context map. */
 72→function setupContextKey(level: SetupLevel, scope: string): string {
 73→  return `${level}:${scope}`;
 74→}
 75→
 76→/**
 77→ * Dispatch a parsed request to the appropriate handler.
 78→ *
 79→ * Returns a Response and a shutdown flag. The handler is async because
 80→ * WASM generator loading requires awaiting plugin creation.
 81→ */
 82→export async function handleRequest(request: Request): Promise<{ response: Response; shutdown: boolean }> {
 83→  if (!isVersionCompatible(request.protocol_version)) {
 84→    return {
 85→      response: errorResponse(request.id, "version_mismatch",
 86→        `Unsupported protocol version: ${request.protocol_version} (expected ${PROTOCOL_VERSION})`),
 87→      shutdown: false,
 88→    };
 89→  }
 90→
 91→  switch (request.command) {
 92→    case "handshake":
 93→      return {
 94→        response: {
 95→          protocol_version: PROTOCOL_VERSION,
 96→          id: request.id,
 97→          status: "handshake",
 98→          frontend_version: PROTOCOL_VERSION,
 99→          language: FRONTEND_LANGUAGE,
100→          capabilities: SUPPORTED_CAPABILITIES,
101→        },
102→        shutdown: false,
103→      };
104→
105→    case "analyze": {
106→      if (!fs.existsSync(request.file)) {
107→        return {
108→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
109→          shutdown: false,
110→        };
111→      }
112→
113→      lastAnalyzedFile = path.resolve(request.file);
114→      setProjectRoot(request.project_root);
115→      const functions = analyzeFile(request.file, request.function, request.project_root);
116→
117→      if (request.function != null && functions.length === 0) {
118→        return {
119→          response: errorResponse(
120→            request.id,
121→            "function_not_found",
122→            `Function not found: ${request.function} in ${request.file}`,
123→          ),
124→          shutdown: false,
125→        };
126→      }
127→
128→      return {
129→        response: {
130→          protocol_version: PROTOCOL_VERSION,
131→          id: request.id,
132→          status: "analyze",
133→          functions,
134→        },
135→        shutdown: false,
136→      };
137→    }
138→
139→    case "instrument": {
140→      if (!fs.existsSync(request.file)) {
141→        return {
142→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
143→          shutdown: false,
144→        };
145→      }
146→
147→      const source = fs.readFileSync(request.file, "utf-8");
148→      const result = instrumentFunction(source, request.function, request.file);
149→
150→      if ("error" in result) {
151→        return {
152→          response: errorResponse(request.id, "instrumentation_failed", result.error),
153→          shutdown: false,
154→        };
155→      }
156→
157→      // Store the instrumented source for use by the execute handler.
158→      // Use resolved path so keys match execute's resolved fileForExec.
159→      const key = `${path.resolve(request.file)}:${request.function}`;
160→      instrumentedSources.set(key, result.instrumentedSource);
161→      lastAnalyzedFile = path.resolve(request.file);
162→
163→      return {
164→        response: {
165→          protocol_version: PROTOCOL_VERSION,
166→          id: request.id,
167→          status: "instrument",
168→          instrumented: true,
169→          output_file: null,
170→          instrumentable_line_count: result.instrumentableLineCount,
171→        },
172→        shutdown: false,
173→      };
174→    }
175→
176→    case "execute": {
177→      const funcRef = request.function;
178→      const fileForExec = resolveFileForExecute(funcRef);
179→
180→      if (!fileForExec) {
181→        return {
182→          response: errorResponse(
183→            request.id,
184→            "function_not_found",
185→            `Cannot resolve file for function: ${funcRef}. Use file:function format.`,
186→          ),
187→          shutdown: false,
188→        };
189→      }
190→
191→      try {
192→        // Check if we have instrumented source for this function
193→        const funcName = funcRef.includes(":") ? funcRef.split(":").pop()! : funcRef;
194→        const instrumentKey = `${fileForExec}:${funcName}`;
195→        const instrumentedSource = instrumentedSources.get(instrumentKey);
196→
197→        let rawResult;
198→        if (instrumentedSource) {
199→          rawResult = await executeInstrumented(instrumentedSource, funcName, request.inputs, request.mocks ?? [], fileForExec);
200→        } else {
201→          rawResult = await executeFunction(fileForExec, funcRef, request.inputs);
202→        }
203→
204→        return {
205→          response: buildExecuteResponse(request.id, PROTOCOL_VERSION, rawResult),
206→          shutdown: false,
207→        };
208→      } catch (e: unknown) {
209→        const msg = e instanceof Error ? e.message : String(e);
210→        return {
211→          response: errorResponse(request.id, "internal_error", `Execute failed: ${msg}`),
212→          shutdown: false,
213→        };
214→      }
215→    }
216→
217→    case "setup": {
218→      if (!fs.existsSync(request.file)) {
219→        return {
220→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
221→          shutdown: false,
222→        };
223→      }
224→
225→      try {
226→        let setupModule = loadedSetupModules.get(request.file);
227→        if (!setupModule) {
228→          setupModule = loadSetupModule(request.file);
229→          loadedSetupModules.set(request.file, setupModule);
230→        }
231→
232→        const setupContext = await runSetup(setupModule, request.scope, request.level, request.parent_context);
233→        const ctxKey = setupContextKey(request.level, request.scope);
234→        setupContexts.set(ctxKey, { module: setupModule, context: setupContext });
235→
236→        return {
237→          response: {
238→            protocol_version: PROTOCOL_VERSION,
239→            id: request.id,
240→            status: "setup",
241→            setup_context: setupContext,
242→          },
243→          shutdown: false,
244→        };
245→      } catch (e: unknown) {
246→        const msg = e instanceof Error ? e.message : String(e);
247→        return {
248→          response: errorResponse(request.id, "internal_error", `Setup failed: ${msg}`),
249→          shutdown: false,
250→        };
251→      }
252→    }
253→
254→    case "teardown": {
255→      try {
256→        const stored = setupContexts.get(request.function);
257→        if (!stored) {
258→          return {
259→            response: errorResponse(
260→              request.id,
261→              "internal_error",
262→              `No setup context found for function: ${request.function}. Call setup first.`,
263→            ),
264→            shutdown: false,
265→          };
266→        }
267→
268→        runTeardown(stored.module, request.function, stored.context);
269→        setupContexts.delete(request.function);
270→        instrumentedSources.clear();
271→        clearModuleCache();
272→
273→        return {
274→          response: {
275→            protocol_version: PROTOCOL_VERSION,
276→            id: request.id,
277→            status: "teardown_ack",
278→          },
279→          shutdown: false,
280→        };
281→      } catch (e: unknown) {
282→        const msg = e instanceof Error ? e.message : String(e);
283→        return {
284→          response: errorResponse(request.id, "internal_error", `Teardown failed: ${msg}`),
285→          shutdown: false,
286→        };
287→      }
288→    }
289→
290→    case "generate": {
291→      if (!fs.existsSync(request.file)) {
292→        return {
293→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
294→          shutdown: false,
295→        };
296→      }
297→
298→      try {
299→        if (request.file.endsWith(".wasm")) {
300→          const plugin = await loadWasmPlugin(request.file);
301→          const result = await runWasmGenerator(plugin, request.name, request.recipe);
302→
303→          return {
304→            response: {
305→              protocol_version: PROTOCOL_VERSION,
306→              id: request.id,
307→              status: "generate",
308→              value: result.value,
309→              generator_id: result.id,
310→              ...(result.recipe !== undefined ? { recipe: result.recipe } : {}),
